import React, { useState, useEffect } from "react";

import "./log-in/login.css";
import { FiArrowRight, FiCheckCircle } from "react-icons/fi";
import { QRCodeCanvas } from "qrcode.react";
import { events } from "../content/events";
import { supabase } from "../database/supabaseClient";

const i18n = events['aid-cuisine'];

// Pretty logger
const LOG = (...args: any[]) =>
  console.log("%c[CHECKOUT]", "color:#FFD700; font-weight:bold;", ...args);

interface CheckoutProps {
  eventData?: any;
}

const EventPayment: React.FC<CheckoutProps> = ({ eventData }) => {
  LOG("🔄 Component RENDER START", { eventSlug: eventData?.slug });

  // 🔐 AUTH
  const [user, setUser] = useState<any>(null);
  const [authLoading, setAuthLoading] = useState(true);

  // 💸 PAYMENT
  const [language, setLanguage] = useState<"EN" | "VN">("EN");
  const [loading, setLoading] = useState(false);
  const [isPaid, setIsPaid] = useState(false);
  const [qrData, setQrData] = useState<any>(null);
  const [transactionId, setTransactionId] = useState<string | null>(null);
  const [testLoading, setTestLoading] = useState(false);

  // Ticket type selection (index of pricing plan)
  const [ticketIndex, setTicketIndex] = useState<number>(0);

  // Derive static text from CMS eventData or fallback
  const fallbackI18n = events['aid-cuisine'];
  const t = eventData ? {
    brandTitle: 'TINH HOA VIỆT',
    tagline: 'Where Vietnamese Excellence Meets Global Recognition',
    features: ['Exclusive Gala Event', 'Cultural Performances', 'Networking with Honorees'],
    title: eventData.checkout?.title || (language === 'EN' ? 'Event Ticket Payment' : 'Thanh Toán Vé Sự Kiện'),
    subtitle: eventData.checkout?.subtitle || (language === 'EN' ? 'Complete your payment to confirm your attendance' : 'Hoàn tất thanh toán để xác nhận tham dự'),
    eventName: eventData.info?.eventName || eventData.eventName,
    date: eventData.info?.eventDate || eventData.date,
    location: eventData.info?.location || 'Saigon, Vietnam',
    price: (language === 'EN' ? 'Ticket Price: ' : 'Giá vé: '),
    payBtn: (language === 'EN' ? 'Pay Now' : 'Thanh toán ngay'),
    loading: (language === 'EN' ? 'Processing payment...' : 'Đang xử lý thanh toán...'),
    success: (language === 'EN' ? 'Payment Confirmed! Thank you.' : 'Thanh toán thành công! Cảm ơn bạn.'),
    testBtn: (language === 'EN' ? 'Test Pay' : 'Kiểm tra thanh toán'),
    langEN: 'EN',
    langVN: 'VN'
  } : fallbackI18n[language];

  const plans = eventData?.pricing || [
    { name: "ENTRY TICKET – PHOTO", price: 200000 },
    { name: "ENTRY TICKET – VIDEO", price: 200000 },
    { name: "ENTRY TICKET – KOC/KOL", price: 200000 }
  ];

  const hydrated = !authLoading;
  const isLoggedInSafe = hydrated && !!user;

  // Scroll to top when checkout view opens
  useEffect(() => {
    window.scrollTo(0, 0);
  }, []);

  LOG("🖨 AUTH SNAPSHOT", { user, authLoading, hydrated, isLoggedInSafe });

  /* ============================================================
     DYNAMIC PRICE
  ============================================================ */
  const getSelectedPrice = () => {
    const plan = plans[ticketIndex];
    if (!plan) return "—";
    return `${plan.price.toLocaleString("vi-VN")}₫`;
  };

  /* ============================================================================
     AUTH INIT
  ============================================================================ */
  useEffect(() => {
    LOG("🔐 AUTH EFFECT MOUNTED");

    let cancelled = false;

    const hydrate = async () => {
      LOG("🔐 Calling supabase.auth.getSession()…");

      try {
        const { data, error } = await supabase.auth.getSession();
        LOG("🔐 getSession() result:", { data, error });

        if (cancelled) return;

        if (data?.session?.user) {
          setUser(data.session.user);
        } else {
          setUser(null);
        }

        setAuthLoading(false);
      } catch (err) {
        setUser(null);
        setAuthLoading(false);
      }
    };

    hydrate();

    const { data: listener } = supabase.auth.onAuthStateChange(
      (_event, session) => {
        if (session?.user) {
          setUser(session.user);
        } else {
          setUser(null);
        }
        setAuthLoading(false);
      }
    );

    return () => {
      cancelled = true;
      listener.subscription.unsubscribe();
    };
  }, []);

  /* ============================================================================
     REALTIME VietQR LISTENER
  ============================================================================ */
  useEffect(() => {
    if (!user) return;

    const channel = supabase
      .channel("public:messages")
      .on(
        "postgres_changes",
        { event: "INSERT", schema: "public", table: "messages" },
        (payload) => {
          try {
            const eventType = payload.new.event_type;
            const eventPayload = payload.new.payload;

            if (eventType !== "vietqr_callback") return;

            const orderId = eventPayload?.orderId;

            if (orderId !== user.id) return;

            setIsPaid(true);
            setQrData(null);
            setTransactionId(eventPayload.transactionid || null);
          } catch { }
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [user?.id]);

  /* ============================================================================
     PAYMENT HANDLER
  ============================================================================ */
  const handlePayment = async () => {
    if (!isLoggedInSafe || !user) {
      window.location.href = "/sign-up";
      return;
    }

    try {
      setLoading(true);
      console.log(user.email);
      const res = await fetch(
        "https://integrations.tinhhoaviet.org.vn/vietqr/payment-intent",
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            user_id: user.id,
            user_email: user.email,
            ticket_type: plans[ticketIndex]?.name || "General",
            amount: plans[ticketIndex]?.price || 0,
          }),
        }
      );

      if (!res.ok) throw new Error("Payment request failed.");

      const data = await res.json();

      if (data?.qrDataURL || data?.qrCode || data?.qrLink) {
        setQrData(data);
      } else {
        alert("QR code missing in response.");
      }
    } catch (err) {
      alert("Payment failed.");
    } finally {
      setLoading(false);
    }
  };

  /* ============================================================================
     TEST CALLBACK
  ============================================================================ */
  const handleTestPayment = async () => {
    if (!qrData) {
      alert("No QR code available.");
      return;
    }

    const payload2 = {
      bankAccount: qrData.bankAccount,
      content: qrData.content,
      amount: qrData.amount,
      bankCode: qrData.bankCode,
      transType: "C",
    };

    try {
      setTestLoading(true);

      const res = await fetch(
        "https://integrations.tinhhoaviet.org.vn/vietqr/test-success",
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(payload2),
        }
      );

      console.log(await res.text());
    } catch (err) {
    } finally {
      setTestLoading(false);
    }
  };

  /* ============================================================================
     RENDER
  ============================================================================ */

  return (
    <div className="auth-shell">
      <aside className="brand-side">
        <div className="brand-sheen" />
        <div className="brand-pattern" />
        <div className="brand-wrap">
          <h1 className="brand-name">{t.brandTitle}</h1>
          <p className="brand-tag">{t.tagline}</p>
          <ul className="brand-features">
            {t.features.map((f: any, i: number) => (
              <li key={i} className="feature">
                <span className="tick">✓</span>
                <span>{f}</span>
              </li>
            ))}
          </ul>
        </div>
      </aside>

      <main className="form-side">
        <header className="form-top">
          <div className="lang-switch">
            <button
              className={`lang ${language === "EN" ? "active" : ""}`}
              onClick={() => setLanguage("EN")}
            >
              {t.langEN}
            </button>
            <span className="mid">|</span>
            <button
              className={`lang ${language === "VN" ? "active" : ""}`}
              onClick={() => setLanguage("VN")}
            >
              {t.langVN}
            </button>
          </div>
        </header>

        <section className="form-wrap" style={{ color: "var(--off-white)" }}>
          <div className="intro">
            <h2 className="title" style={{ color: "var(--off-white)" }}>
              {t.title}
            </h2>
            <p className="subtitle" style={{ color: "var(--light-gray)" }}>
              {t.subtitle}
            </p>
          </div>

          <div className="auth-form" style={{ textAlign: "center" }}>
            <div className="field">
              <h3
                style={{
                  color: "var(--gold-2)",
                  fontSize: 22,
                  marginBottom: 6,
                }}
              >
                {t.eventName}
              </h3>

              <p style={{ color: "var(--off-white)" }}>{t.date}</p>
              <p style={{ color: "var(--off-white)" }}>{t.location}</p>

              <p
                style={{
                  fontWeight: 700,
                  marginTop: 10,
                  color: "var(--off-white)",
                  fontSize: "1.1rem",
                }}
              >
                {language === "EN" ? "Ticket Price: " : "Giá vé: "}
                {getSelectedPrice()}
              </p>
            </div>

            {/* CATEGORY SELECTOR */}
            <div style={{ marginTop: 25, marginBottom: 25 }}>
              <h4
                style={{
                  fontWeight: 700,
                  marginBottom: 12,
                  color: "var(--gold-2)",
                }}
              >
                {language === "EN"
                  ? "Choose Entry Category"
                  : "Chọn Hạng Mục Tham Gia"}
              </h4>

              <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
                {plans.map((plan: any, idx: number) => (
                  <label
                    key={idx}
                    onClick={() => setTicketIndex(idx)}
                    style={{
                      padding: "14px 18px",
                      borderRadius: 12,
                      cursor: "pointer",
                      display: "flex",
                      alignItems: "center",
                      gap: 12,
                      border:
                        ticketIndex === idx
                          ? "2px solid var(--gold-2)"
                          : "1px solid var(--medium-gray)",
                    }}
                  >
                    <span style={{ fontSize: "1.6rem" }}>🎟️</span>
                    <div style={{ textAlign: "left", color: "var(--off-white)" }}>
                      <div style={{ fontWeight: 700 }}>
                        {plan.name}
                      </div>
                      <div
                        style={{
                          color: "var(--light-gray)",
                          fontSize: "0.9rem",
                        }}
                      >
                        {plan.price.toLocaleString("vi-VN")}₫
                      </div>
                    </div>
                    <input
                      type="radio"
                      checked={ticketIndex === idx}
                      readOnly
                      style={{ marginLeft: "auto" }}
                    />
                  </label>
                ))}
              </div>
            </div>

            {/* PAID STATE */}
            {isPaid ? (
              <div
                style={{
                  marginTop: 20,
                  color: "var(--gold-2)",
                  fontWeight: 700,
                  display: "flex",
                  flexDirection: "column",
                  alignItems: "center",
                }}
              >
                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                  <FiCheckCircle size={22} /> {t.success}
                </div>
                {transactionId && (
                  <p style={{ marginTop: 4, color: "var(--off-white)" }}>
                    Transaction ID: <strong>{transactionId}</strong>
                  </p>
                )}
              </div>
            ) : (
              <>
                {/* QR DISPLAY */}
                {qrData && (qrData.qrDataURL || qrData.qrCode) && (
                  <div style={{ marginTop: 20 }}>
                    <QRCodeCanvas
                      value={qrData.qrDataURL || qrData.qrCode}
                      size={220}
                      includeMargin={true}
                    />
                    <p style={{ marginTop: 12, color: "var(--gold-2)" }}>
                      Scan this code to complete your payment.
                    </p>
                  </div>
                )}

                {/* PAY BUTTON */}
                {!qrData ? (
                  <button
                    className="cta"
                    onClick={handlePayment}
                    disabled={loading}
                    style={{
                      opacity: loading ? 0.6 : 1,
                      cursor: loading ? "not-allowed" : "pointer",
                    }}
                  >
                    <span>
                      {!hydrated
                        ? "Checking login..."
                        : !isLoggedInSafe
                          ? language === "EN"
                            ? "Login / Sign Up"
                            : "Đăng nhập / Đăng ký"
                          : loading
                            ? t.loading
                            : t.payBtn}
                    </span>

                    {isLoggedInSafe && !loading && hydrated && (
                      <FiArrowRight className="arrow" />
                    )}
                  </button>
                ) : (
                  <button
                    className="cta"
                    onClick={handleTestPayment}
                    disabled={testLoading}
                    style={{
                      backgroundColor: "#00b37a",
                      marginTop: 10,
                      opacity: testLoading ? 0.7 : 1,
                    }}
                  >
                    {testLoading ? "⏳" : t.testBtn}
                  </button>
                )}
              </>
            )}
          </div>
        </section>
      </main>
    </div>
  );
};

export default EventPayment;
